import { useCamera, type CameraInstance } from '../composables/useCamera';
import { useDecoder, type DecoderInstance } from '../composables/useDecoder';
import type {
  BinarizerStrategy,
  DecoderStats,
  ScannerError,
  ScannerStatus,
} from '../types';
import { SHADOW_HTML, SHADOW_STYLES } from './template';

const HINT_BY_STATUS: Record<ScannerStatus, string> = {
  idle: '',
  initializing: '初期化中…',
  requesting_camera: 'カメラを要求しています…',
  running: '枠に合わせて少し離してください',
  paused: '',
  error: '',
};

function parseBoolAttr(value: string | null, fallback: boolean): boolean {
  if (value === null) return fallback;
  if (value === 'false' || value === '0') return false;
  return true;
}

function parseNumberAttr(value: string | null, fallback: number): number {
  if (value === null || value === '') return fallback;
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function isBinarizerStrategy(s: string): s is BinarizerStrategy {
  return s === 'auto' || s === 'otsu' || s === 'adaptive_mean' || s === 'sauvola';
}

const OBSERVED_ATTRS = [
  'roi-size',
  'debounce-ms',
  'auto-start',
  'binarizer-strategy',
  'show-stats',
  'prefer-zoom',
] as const;

// SSR / Node 環境でもこのモジュールが import 可能になるよう、
// HTMLElement が無ければ no-op 基底にフォールバックする。
const ElementBase: typeof HTMLElement =
  typeof HTMLElement !== 'undefined'
    ? HTMLElement
    : (class {} as unknown as typeof HTMLElement);

export class QrScannerElement extends ElementBase {
  static get observedAttributes(): readonly string[] {
    return OBSERVED_ATTRS;
  }

  private _videoConstraints: MediaTrackConstraints = {};
  private _camera: CameraInstance | null = null;
  private _decoder: DecoderInstance | null = null;
  private _flashTimer: ReturnType<typeof setTimeout> | null = null;
  private _started = false;
  private _hintEl: HTMLElement | null = null;
  private _errorEl: HTMLElement | null = null;
  private _statsEls: Record<string, HTMLElement | null> = {};
  private _videoEl: HTMLVideoElement | null = null;
  private _currentStatus: ScannerStatus = 'idle';

  constructor() {
    super();
    const shadow = this.attachShadow({ mode: 'open' });
    const style = document.createElement('style');
    style.textContent = SHADOW_STYLES;
    shadow.appendChild(style);
    const wrapper = document.createElement('div');
    wrapper.innerHTML = SHADOW_HTML;
    while (wrapper.firstChild) {
      shadow.appendChild(wrapper.firstChild);
    }

    this._videoEl = shadow.querySelector('video');
    this._hintEl = shadow.querySelector('.hint');
    this._errorEl = shadow.querySelector('.error');
    this._statsEls = {
      state: shadow.querySelector('[data-stats="state"]'),
      frames: shadow.querySelector('[data-stats="frames"]'),
      decoded: shadow.querySelector('[data-stats="decoded"]'),
      bin: shadow.querySelector('[data-stats="bin"]'),
      last: shadow.querySelector('[data-stats="last"]'),
    };
  }

  connectedCallback(): void {
    if (this._started) return;
    if (this.getAutoStart()) {
      // 次のマイクロタスクで起動（属性反映を待つ）
      queueMicrotask(() => this.start());
    }
  }

  disconnectedCallback(): void {
    this.stop();
  }

  attributeChangedCallback(name: string, _old: string | null, _next: string | null): void {
    if (name === 'binarizer-strategy' && this._decoder) {
      this._decoder.setStrategy(this.getBinarizerStrategy());
    }
  }

  // ---------- public DOM API ----------

  get videoConstraints(): MediaTrackConstraints {
    return this._videoConstraints;
  }
  set videoConstraints(v: MediaTrackConstraints) {
    this._videoConstraints = v || {};
  }

  async start(): Promise<void> {
    if (this._started) return;
    if (!this._videoEl) return;
    this._started = true;
    this.removeAttribute('data-has-error');
    if (this._errorEl) this._errorEl.textContent = '';

    if (!this._camera) {
      this._camera = useCamera({
        videoConstraints: this._videoConstraints,
        preferZoom: this.getPreferZoom(),
        onError: (e) => this.emitError(e),
      });
    }

    if (!this._decoder) {
      this._decoder = useDecoder({
        roiSize: this.getRoiSize(),
        debounceMs: this.getDebounceMs(),
        binarizerStrategy: this.getBinarizerStrategy(),
        onDecoded: (payload, stats) => {
          this.flash();
          this.updateStats(stats);
          this.dispatchEvent(
            new CustomEvent('decoded', {
              detail: { payload, stats },
              bubbles: false,
              composed: true,
            }),
          );
        },
        onStats: (stats) => this.updateStats(stats),
        onStatusChange: (status) => {
          this._currentStatus = status;
          this.updateHint();
          this.dispatchEvent(
            new CustomEvent('status', {
              detail: { status },
              bubbles: false,
              composed: true,
            }),
          );
        },
        onError: (e) => this.emitError(e),
      });
    }

    try {
      await this._camera.start(this._videoEl);
      await this._decoder.start(this._videoEl);
    } catch (e) {
      const err: ScannerError = {
        code: 'unknown',
        message: e instanceof Error ? e.message : String(e),
        cause: e,
      };
      this.emitError(err);
    }
  }

  stop(): void {
    if (this._decoder) this._decoder.stop();
    if (this._camera) this._camera.stop();
    if (this._flashTimer) {
      clearTimeout(this._flashTimer);
      this._flashTimer = null;
    }
    this.removeAttribute('data-flashing');
    this._started = false;
  }

  // ---------- internal ----------

  private getRoiSize(): number {
    return parseNumberAttr(this.getAttribute('roi-size'), 400);
  }

  private getDebounceMs(): number {
    return parseNumberAttr(this.getAttribute('debounce-ms'), 2000);
  }

  private getAutoStart(): boolean {
    return parseBoolAttr(this.getAttribute('auto-start'), true);
  }

  private getPreferZoom(): number {
    return parseNumberAttr(this.getAttribute('prefer-zoom'), 0);
  }

  private getBinarizerStrategy(): BinarizerStrategy {
    const v = this.getAttribute('binarizer-strategy');
    if (v && isBinarizerStrategy(v)) return v;
    return 'auto';
  }

  private flash(): void {
    this.setAttribute('data-flashing', '');
    if (this._flashTimer) clearTimeout(this._flashTimer);
    this._flashTimer = setTimeout(() => {
      this.removeAttribute('data-flashing');
      this._flashTimer = null;
    }, 300);
  }

  private updateStats(s: DecoderStats): void {
    if (this._statsEls.state) this._statsEls.state.textContent = `state: ${this._currentStatus}`;
    if (this._statsEls.frames) this._statsEls.frames.textContent = `frames: ${s.framesProcessed}`;
    if (this._statsEls.decoded) this._statsEls.decoded.textContent = `decoded: ${s.framesDecoded}`;
    if (this._statsEls.bin) this._statsEls.bin.textContent = `bin: ${s.lastBinarizerUsed || '—'}`;
    if (this._statsEls.last) this._statsEls.last.textContent = `last: ${s.lastDecodeMs.toFixed(1)}ms`;
  }

  private updateHint(): void {
    if (!this._hintEl) return;
    this._hintEl.textContent = HINT_BY_STATUS[this._currentStatus] || '';
  }

  private emitError(err: ScannerError): void {
    this.setAttribute('data-has-error', '');
    if (this._errorEl) this._errorEl.textContent = err.message;
    this.dispatchEvent(
      new CustomEvent('error', {
        detail: { error: err },
        bubbles: false,
        composed: true,
      }),
    );
  }
}

const DEFAULT_TAG = 'qr-scanner';

export function defineQrScannerElement(tagName: string = DEFAULT_TAG): void {
  if (typeof customElements === 'undefined') return;
  if (customElements.get(tagName)) return;
  customElements.define(tagName, QrScannerElement);
}

// import 副作用で自動登録
defineQrScannerElement();
