// Shadow DOM 内に注入する style 定義。CSS 変数経由で外から theming できる。
export const SHADOW_STYLES = `
  :host {
    --qr-bg: #000;
    --qr-guide-color: rgba(255, 255, 255, 0.9);
    --qr-guide-flash-color: #4ade80;
    --qr-guide-corner-thickness: 4px;
    --qr-guide-corner-length: 32px;
    --qr-guide-frame-size: min(60vmin, 400px);
    --qr-stats-bg: rgba(0, 0, 0, 0.55);
    --qr-stats-color: #f5f5f5;
    --qr-stats-font: 12px / 1.5 ui-monospace, SFMono-Regular, Menlo, monospace;
    --qr-error-bg: #b91c1c;
    --qr-error-color: #fff;
    --qr-hint-color: rgba(255, 255, 255, 0.85);
    --qr-hint-bg: rgba(0, 0, 0, 0.4);

    display: block;
    position: relative;
    width: 100%;
    height: 100%;
    min-height: 320px;
    background: var(--qr-bg);
    overflow: hidden;
  }

  .video {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
    background: var(--qr-bg);
  }

  .guide {
    position: absolute;
    inset: 0;
    pointer-events: none;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-direction: column;
    gap: 12px;
  }

  .guide__frame {
    position: relative;
    width: var(--qr-guide-frame-size);
    height: var(--qr-guide-frame-size);
  }

  .guide__corner {
    position: absolute;
    width: var(--qr-guide-corner-length);
    height: var(--qr-guide-corner-length);
    border-color: var(--qr-guide-color);
    border-style: solid;
    border-width: 0;
    transition: border-color 0.2s ease;
  }

  .guide__corner--tl { top: 0; left: 0; border-top-width: var(--qr-guide-corner-thickness); border-left-width: var(--qr-guide-corner-thickness); }
  .guide__corner--tr { top: 0; right: 0; border-top-width: var(--qr-guide-corner-thickness); border-right-width: var(--qr-guide-corner-thickness); }
  .guide__corner--bl { bottom: 0; left: 0; border-bottom-width: var(--qr-guide-corner-thickness); border-left-width: var(--qr-guide-corner-thickness); }
  .guide__corner--br { bottom: 0; right: 0; border-bottom-width: var(--qr-guide-corner-thickness); border-right-width: var(--qr-guide-corner-thickness); }

  :host([data-flashing]) .guide__corner {
    border-color: var(--qr-guide-flash-color);
  }

  .hint {
    margin: 0;
    padding: 6px 12px;
    border-radius: 999px;
    background: var(--qr-hint-bg);
    color: var(--qr-hint-color);
    font-size: 14px;
    letter-spacing: 0.02em;
  }

  .stats {
    position: absolute;
    top: 12px;
    left: 12px;
    display: none;
    flex-direction: column;
    gap: 4px;
    padding: 8px 12px;
    background: var(--qr-stats-bg);
    color: var(--qr-stats-color);
    font: var(--qr-stats-font);
    border-radius: 6px;
    pointer-events: none;
  }

  :host([show-stats]) .stats {
    display: flex;
  }

  .error {
    position: absolute;
    bottom: 16px;
    left: 50%;
    transform: translateX(-50%);
    background: var(--qr-error-bg);
    color: var(--qr-error-color);
    padding: 8px 16px;
    border-radius: 6px;
    max-width: 80%;
    text-align: center;
    display: none;
  }

  :host([data-has-error]) .error {
    display: block;
  }
`;

export const SHADOW_HTML = `
  <video class="video" autoplay playsinline muted></video>
  <slot name="guide">
    <div class="guide" part="guide">
      <div class="guide__frame">
        <span class="guide__corner guide__corner--tl"></span>
        <span class="guide__corner guide__corner--tr"></span>
        <span class="guide__corner guide__corner--bl"></span>
        <span class="guide__corner guide__corner--br"></span>
      </div>
      <p class="hint" part="hint"></p>
    </div>
  </slot>
  <slot name="overlay"></slot>
  <div class="stats" part="stats">
    <span data-stats="state"></span>
    <span data-stats="frames"></span>
    <span data-stats="decoded"></span>
    <span data-stats="bin"></span>
    <span data-stats="last"></span>
  </div>
  <div class="error" part="error"></div>
`;
